export async function GET(request: NextRequest) {
  try {
    const admin = await verifyAdmin(request);
    if (!admin) return unauthorized();

    const { page, pageSize } = getPaginationParams(request.url);
    const companyId = request.nextUrl.searchParams.get('company_id');

    let whereClause = '';
    const params: any[] = [];
    let paramIdx = 1;

    if (companyId) {
      whereClause = `WHERE u.company_id = $${paramIdx}`;
      params.push(companyId);
      paramIdx++;
    }

    const countRes = await query(
      `SELECT COUNT(*)::int as total FROM users u ${whereClause}`,
      params
    );
    const total = countRes.rows[0].total;

    params.push(pageSize, (page - 1) * pageSize);

    const res = await query(
      `SELECT u.id, u.name, u.email, u.role, u.is_active, u.last_login,
              u.created_at, u.company_id,
              c.name as company_name
       FROM users u
       JOIN companies c ON c.id = u.company_id
       ${whereClause}
       ORDER BY u.created_at DESC
       LIMIT $${paramIdx} OFFSET $${paramIdx + 1}`,
      params
    );

    return success({
      users: res.rows,
      total,
      page,
      pageSize,
    });
  } catch (err) {
    return serverError(err);
  }
}

import { NextRequest } from 'next/server';
import { success, error, unauthorized, serverError, notFound, parseBody } from '@/lib/api-helpers';
import { query, transaction } from '@/lib/db';
import { verifyPassword, verifyToken } from '@/lib/auth';

async function verifyAdmin(request: NextRequest) {
  const token = request.cookies.get('admin_token')?.value;
  if (!token) return null;
  const payload = verifyToken(token);
  if (!payload || payload.role !== 'superadmin') return null;
  return payload;
}

export async function PATCH(
  request: NextRequest,
  { params: paramsPromise }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await paramsPromise;
    const admin = await verifyAdmin(request);
    if (!admin) return unauthorized();

    const masterHeader = request.headers.get('x-master-password');
    if (!masterHeader) {
      return error('كلمة المرور الرئيسية مطلوبة في ترويسة x-master-password', 401);
    }

    const body = await parseBody<{ is_active: boolean }>(request);
    if (typeof body.is_active !== 'boolean') {
      return error('is_active يجب أن يكون true أو false');
    }

    const adminRes = await query(
      `SELECT master_password_hash FROM admin_users WHERE id = $1`,
      [admin.userId]
    );

    if (adminRes.rows.length === 0) {
      return error('المسؤول غير موجود', 401);
    }

    const masterHash = adminRes.rows[0].master_password_hash;
    const valid = await verifyPassword(masterHeader, masterHash);
    if (!valid) {
      return error('كلمة المرور الرئيسية غير صحيحة', 401);
    }

    const companyRes = await query(
      `SELECT id, name, is_active FROM companies WHERE id = $1`,
      [id]
    );

    if (companyRes.rows.length === 0) {
      return notFound();
    }

    const company = companyRes.rows[0];

    await transaction(async (client) => {
      await client.query(
        `UPDATE companies SET is_active = $1, updated_at = NOW()::timestamp WHERE id = $2`,
        [body.is_active, id]
      );

      await client.query(
        `INSERT INTO admin_audit_log (admin_id, action, target_type, target_id, details)
         VALUES ($1, $2, 'company', $3, $4)`,
        [
          admin.userId,
          body.is_active ? 'activate_company' : 'deactivate_company',
          id,
          JSON.stringify({ companyName: company.name, previousState: company.is_active }),
        ]
      );
    });

    return success({
      message: body.is_active ? 'تم تفعيل الشركة بنجاح' : 'تم إيقاف الشركة بنجاح',
    });
  } catch (err) {
    return serverError(err);
  }
}

import { NextRequest } from 'next/server';
import { success, error, serverError, parseBody } from '@/lib/api-helpers';
import { query, transaction } from '@/lib/db';
import { verifyPassword, createToken } from '@/lib/auth';
import { getAdminSession, deleteAdminSession } from '@/lib/admin-session';

export async function POST(request: NextRequest) {
  try {
    const { email, masterPassword } = await parseBody<{ email: string; masterPassword: string }>(request);

    if (!masterPassword) {
      return error('كلمة المرور الرئيسية مطلوبة');
    }

    const sessionId = request.cookies.get('admin_session')?.value;
    if (!sessionId) {
      return error('انتهت صلاحية الجلسة. يرجى تسجيل الدخول مرة أخرى', 401);
    }

    const session = getAdminSession(sessionId);
    if (!session) {
      return error('انتهت صلاحية الجلسة. يرجى تسجيل الدخول مرة أخرى', 401);
    }

    if (session.email !== email.trim().toLowerCase()) {
      return error('البريد الإلكتروني غير متطابق مع الجلسة', 401);
    }

    if (session.step !== 'telegram_verified') {
      return error('يرجى التحقق من رمز تيليجرام أولاً', 401);
    }

    const res = await query(
      `SELECT id, name, email, master_password_hash, is_active
       FROM admin_users
       WHERE email = LOWER($1)`,
      [session.email]
    );

    if (res.rows.length === 0) {
      return error('المستخدم غير موجود', 401);
    }

    const admin = res.rows[0];

    if (!admin.is_active) {
      return error('هذا الحساب غير نشط', 403);
    }

    if (!admin.master_password_hash) {
      return error('لم يتم تعيين كلمة مرور رئيسية لهذا الحساب', 403);
    }

    const valid = await verifyPassword(masterPassword, admin.master_password_hash);
    if (!valid) {
      return error('كلمة المرور الرئيسية غير صحيحة', 401);
    }

    const token = createToken(admin.id, 'superadmin');

    deleteAdminSession(sessionId);

    const response = success({
      message: 'تم تسجيل الدخول بنجاح',
      admin: {
        id: admin.id,
        name: admin.name,
        email: admin.email,
        role: 'superadmin',
      },
      token,
    });

    response.cookies.set('admin_token', token, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'lax',
      maxAge: 86400,
      path: '/',
    });

    response.cookies.set('admin_session', '', {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'strict',
      maxAge: 0,
      path: '/',
    });

    return response;
  } catch (err) {
    return serverError(err);
  }
}

'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import {
  Users, Search, Loader2, ShieldAlert, RefreshCw,
  CheckCircle, XCircle, ChevronLeft, Filter, Eye
} from 'lucide-react';
import Link from 'next/link';

const ADMIN_TOKEN_KEY = 'zerocold_token';

interface AppUser {
  id: string;
  name: string;
  email: string;
  company_name: string;
  company_id: string;
  role: string;
  status: 'active' | 'suspended';
  last_login: string | null;
}

export default function ZerocoldUsersPage() {
  const router = useRouter();
  const [users, setUsers] = useState<AppUser[]>([]);
  const [companies, setCompanies] = useState<{ id: string; name: string }[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [search, setSearch] = useState('');
  const [companyFilter, setCompanyFilter] = useState('');
  const [actionLoading, setActionLoading] = useState<string | null>(null);
  const [selectedUser, setSelectedUser] = useState<AppUser | null>(null);
  const [userActivity, setUserActivity] = useState<{ action: string; timestamp: string }[]>([]);
  const [activityLoading, setActivityLoading] = useState(false);

  const fetchData = async () => {
    setLoading(true);
    setError('');
    try {
      const token = localStorage.getItem(ADMIN_TOKEN_KEY);
      if (!token) {
        router.replace('/zerocold/login');
        return;
      }

      const [usersRes, companiesRes] = await Promise.all([
        fetch('/api/admin/users', { headers: { Authorization: `Bearer ${token}` } }),
        fetch('/api/admin/companies', { headers: { Authorization: `Bearer ${token}` } }),
      ]);

      if (usersRes.status === 401) {
        localStorage.removeItem(ADMIN_TOKEN_KEY);
        router.replace('/zerocold/login');
        return;
      }

      const usersBody = await usersRes.json();
      const companiesBody = await companiesRes.json();

      if (!usersBody.success) {
        setError(usersBody.message || 'حدث خطأ');
        return;
      }

      setUsers(usersBody.data);
      if (companiesBody.success) {
        setCompanies(companiesBody.data);
      }
    } catch {
      setError('حدث خطأ في الاتصال بالخادم');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const toggleStatus = async (userId: string) => {
    setActionLoading(userId);
    try {
      const token = localStorage.getItem(ADMIN_TOKEN_KEY);
      const res = await fetch('/api/admin/users/toggle-status', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
        body: JSON.stringify({ userId }),
      });

      const body = await res.json();
      if (!res.ok || !body.success) return;

      setUsers((prev) =>
        prev.map((u) =>
          u.id === userId
            ? { ...u, status: u.status === 'active' ? 'suspended' : 'active' }
            : u
        )
      );
    } catch {} finally {
      setActionLoading(null);
    }
  };

  const showUserActivity = async (user: AppUser) => {
    setSelectedUser(user);
    setActivityLoading(true);
    try {
      const token = localStorage.getItem(ADMIN_TOKEN_KEY);
      const res = await fetch(`/api/admin/users/${user.id}/activity`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const body = await res.json();
      setUserActivity(body.success ? body.data : []);
    } catch {
      setUserActivity([]);
    } finally {
      setActivityLoading(false);
    }
  };

  const filtered = users.filter((u) => {
    const matchesSearch =
      u.name.toLowerCase().includes(search.toLowerCase()) ||
      u.email.toLowerCase().includes(search.toLowerCase());
    const matchesCompany = !companyFilter || u.company_id === companyFilter;
    return matchesSearch && matchesCompany;
  });

  const roleLabels: Record<string, string> = {
    admin: 'مدير',
    accountant: 'محاسب',
    manager: 'مشرف',
    supervisor: 'مراقب',
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-[#0a0a0f] flex items-center justify-center">
        <Loader2 size={32} className="text-amber-500 animate-spin" />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#0a0a0f]">
      <div className="max-w-6xl mx-auto px-4 py-6">
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-3">
            <Link href="/zerocold/" className="p-2 rounded-lg hover:bg-[#12101a] transition-all">
              <ChevronLeft size={18} className="text-amber-500/70" />
            </Link>
            <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-emerald-600 to-green-700 flex items-center justify-center">
              <Users className="w-5 h-5 text-white" />
            </div>
            <div>
              <h1 className="text-lg font-bold text-amber-50">إدارة المستخدمين</h1>
              <p className="text-[0.7rem] text-amber-400/50">{users.length} مستخدم</p>
            </div>
          </div>
          <button
            onClick={fetchData}
            className="p-2 rounded-xl bg-[#12101a] border border-[#2a1f0a] text-amber-500/70 hover:text-amber-400 transition-all"
            title="تحديث"
          >
            <RefreshCw size={16} />
          </button>
        </div>

        <div className="flex items-center gap-3 mb-4">
          <div className="relative flex-1">
            <Search size={16} className="absolute right-3 top-1/2 -translate-y-1/2 text-amber-600/50" />
            <input
              type="text"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="بحث عن مستخدم..."
              className="w-full pr-10 pl-4 py-2.5 bg-[#12101a] border border-[#2a1f0a] rounded-xl text-amber-50 placeholder-amber-700/50 focus:outline-none focus:border-amber-600 focus:ring-1 focus:ring-amber-600/30 transition-all text-sm"
            />
          </div>
          <div className="relative">
            <Filter size={16} className="absolute right-3 top-1/2 -translate-y-1/2 text-amber-600/50 pointer-events-none" />
            <select
              value={companyFilter}
              onChange={(e) => setCompanyFilter(e.target.value)}
              className="pr-10 pl-4 py-2.5 bg-[#12101a] border border-[#2a1f0a] rounded-xl text-amber-50 focus:outline-none focus:border-amber-600 focus:ring-1 focus:ring-amber-600/30 transition-all text-sm appearance-none cursor-pointer"
            >
              <option value="">كل الشركات</option>
              {companies.map((c) => (
                <option key={c.id} value={c.id}>{c.name}</option>
              ))}
            </select>
          </div>
        </div>

        {error && (
          <div className="bg-red-950/40 border border-red-800/40 text-red-400 text-sm rounded-xl px-4 py-2.5 text-center mb-4">
            {error}
          </div>
        )}

        {filtered.length === 0 && !error ? (
          <div className="bg-[#12101a] border border-[#2a1f0a] rounded-xl p-8 text-center">
            <Users size={32} className="text-amber-600/30 mx-auto mb-2" />
            <p className="text-amber-600/50 text-sm">لا يوجد مستخدمون مطابقون للبحث</p>
          </div>
        ) : (
          <div className="bg-[#12101a] border border-[#2a1f0a] rounded-xl overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="border-b border-[#2a1f0a]">
                    <th className="text-right p-3 text-[0.7rem] text-amber-500/60 font-medium">الاسم</th>
                    <th className="text-right p-3 text-[0.7rem] text-amber-500/60 font-medium">البريد الإلكتروني</th>
                    <th className="text-right p-3 text-[0.7rem] text-amber-500/60 font-medium">الشركة</th>
                    <th className="text-center p-3 text-[0.7rem] text-amber-500/60 font-medium">الدور</th>
                    <th className="text-center p-3 text-[0.7rem] text-amber-500/60 font-medium">الحالة</th>
                    <th className="text-right p-3 text-[0.7rem] text-amber-500/60 font-medium">آخر دخول</th>
                    <th className="text-center p-3 text-[0.7rem] text-amber-500/60 font-medium">الإجراءات</th>
                  </tr>
                </thead>
                <tbody>
                  {filtered.map((user) => (
                    <tr key={user.id} className="border-b border-[#1f1725] last:border-0 hover:bg-[#1a1625] transition-all">
                      <td className="p-3">
                        <span className="text-sm text-amber-200 font-medium">{user.name}</span>
                      </td>
                      <td className="p-3">
                        <span className="text-xs text-amber-400/60 font-mono" dir="ltr">{user.email}</span>
                      </td>
                      <td className="p-3">
                        <span className="text-xs text-amber-400/80">{user.company_name}</span>
                      </td>
                      <td className="p-3 text-center">
                        <span className="text-xs text-amber-400/60">{roleLabels[user.role] || user.role}</span>
                      </td>
                      <td className="p-3 text-center">
                        <span
                          className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[0.65rem] font-medium ${
                            user.status === 'active'
                              ? 'bg-emerald-950/40 text-emerald-400 border border-emerald-800/30'
