import { NextRequest } from 'next/server';
import { success, error, serverError, parseBody } from '@/lib/api-helpers';
import { query } from '@/lib/db';
import { verifyPassword } from '@/lib/auth';
import { adminLoginSchema } from '@/lib/validation';
import { sendTelegramCode } from '@/lib/telegram';
import { generateId } from '@/lib/utils';
import { createAdminSession, updateAdminSession } from '@/lib/admin-session';

export async function POST(request: NextRequest) {
  try {
    const body = await parseBody<{ email: string; password: string }>(request);
    const parsed = adminLoginSchema.safeParse(body);
    if (!parsed.success) {
      return error('البريد الإلكتروني أو كلمة المرور غير صالحة');
    }

    const { email, password } = parsed.data;

    const res = await query(
      `SELECT id, name, email, password_hash, is_active
       FROM admin_users
       WHERE email = LOWER($1)`,
      [email]
    );

    if (res.rows.length === 0) {
      return error('البريد الإلكتروني أو كلمة المرور غير صحيحة', 401);
    }

    const admin = res.rows[0];

    if (!admin.is_active) {
      return error('هذا الحساب غير نشط', 403);
    }

    const valid = await verifyPassword(password, admin.password_hash);
    if (!valid) {
      return error('البريد الإلكتروني أو كلمة المرور غير صحيحة', 401);
    }

    const sessionId = generateId();
    const code = String(Math.floor(100000 + Math.random() * 900000));

    createAdminSession(sessionId, admin.email, code);

    await sendTelegramCode(code);

    updateAdminSession(sessionId, { codeSent: true });

    const response = success({
      message: 'تم إرسال رمز التحقق إلى تيليجرام',
      email: admin.email,
    });

    response.cookies.set('admin_session', sessionId, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'strict',
      maxAge: 1800,
      path: '/',
    });

    return response;
  } catch (err) {
    return serverError(err);
  }
}

'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import {
  Building2, Search, Loader2, ShieldAlert, RefreshCw,
  CheckCircle, XCircle, Eye, ChevronLeft
} from 'lucide-react';
import Link from 'next/link';

const ADMIN_TOKEN_KEY = 'zerocold_token';

interface Company {
  id: string;
  name: string;
  registration_number: string;
  tax_number: string;
  users_count: number;
  created_at: string;
  status: 'active' | 'suspended';
}

export default function ZerocoldCompaniesPage() {
  const router = useRouter();
  const [companies, setCompanies] = useState<Company[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [search, setSearch] = useState('');
  const [actionLoading, setActionLoading] = useState<string | null>(null);

  const fetchCompanies = async () => {
    setLoading(true);
    setError('');
    try {
      const token = localStorage.getItem(ADMIN_TOKEN_KEY);
      if (!token) {
        router.replace('/zerocold/login');
        return;
      }

      const res = await fetch('/api/admin/companies', {
        headers: { Authorization: `Bearer ${token}` },
      });

      if (res.status === 401) {
        localStorage.removeItem(ADMIN_TOKEN_KEY);
        router.replace('/zerocold/login');
        return;
      }

      const body = await res.json();
      if (!body.success) {
        setError(body.message || 'حدث خطأ');
        return;
      }

      setCompanies(body.data);
    } catch {
      setError('حدث خطأ في الاتصال بالخادم');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchCompanies();
  }, []);

  const toggleStatus = async (companyId: string, currentStatus: string) => {
    setActionLoading(companyId);
    try {
      const token = localStorage.getItem(ADMIN_TOKEN_KEY);
      const res = await fetch('/api/admin/companies/toggle-status', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
        body: JSON.stringify({ companyId }),
      });

      const body = await res.json();

      if (!res.ok || !body.success) {
        if (body.masterRequired) {
          router.push('/zerocold/verify-master');
          return;
        }
        return;
      }

      setCompanies((prev) =>
        prev.map((c) =>
          c.id === companyId
            ? { ...c, status: currentStatus === 'active' ? 'suspended' : 'active' }
            : c
        )
      );
    } catch {} finally {
      setActionLoading(null);
    }
  };

  const filtered = companies.filter((c) =>
    c.name.toLowerCase().includes(search.toLowerCase()) ||
    c.registration_number?.toLowerCase().includes(search.toLowerCase()) ||
    c.tax_number?.toLowerCase().includes(search.toLowerCase())
  );

